import {TriStateCheckbox as TriStateCheckboxMobile, type TriStateCheckboxProps} from "@lmb-it/kitsconcertomobile";
import {useSelectionController} from "../../../hooks";

export const TriStateCheckbox = (props:TriStateCheckboxProps)=>{
    const { value, onChange } = useSelectionController({
        mode: 'tristate',
        defaultValue: false // Start at false
    });

    return <TriStateCheckboxMobile value={value} onChange={()=>onChange()} {...props} />
}
